package main

import "fmt"

func wordBreak(s string, wordDict []string) bool {
    wordSet := make(map[string]struct{})
    for _, word := range wordDict {
        wordSet[word] = struct{}{}
    }
    return canSegment(s, wordSet)
}

func canSegment(s string, wordSet map[string]struct{}) bool {
    if s == "" {
        return true
    }
    for i := 1; i <= len(s); i++ {
        if _, exists := wordSet[s[:i]]; exists {
            if canSegment(s[i:], wordSet) {
                return true
            }
        }
    }
    return false
}

func main() {
    fmt.Println(wordBreak("leetcode", []string{"leet", "code"})) // true
    fmt.Println(wordBreak("applepenapple", []string{"apple", "pen"})) // true
    fmt.Println(wordBreak("catsandog", []string{"cats", "dog", "sand", "and", "cat"})) // false
}

