        if (start == s.Length) {
            return true;
        }

        for (int end = start + 1; end <= s.Length; end++) {
            String prefix = s.Substring(start, end - start);
            if (wordDict.Contains(prefix) && WordBreakHelper(s, wordDict, end)) {
                return true;
            }
        }

        return false;
    }
}

