func wordBreak(s string, wordDict []string) bool {
    wordSet := make(map[string]struct{})
    for _, word := range wordDict {
        wordSet[word] = struct{}{}
    }
    n := len(s)
    dp := make([]bool, n+1)
    dp[0] = true

    for i := 1; i <= n; i++ {
        for j := 0; j < i; j++ {
            if dp[j] {
                if _, exists := wordSet[s[j:i]]; exists {
                    dp[i] = true
                    break
                }
            }
        }
    }
    return dp[n]
}

